        usedGb: usedGb != null ? Math.round(usedGb * 10) / 10 : null,
        usedMb: usedGb != null ? Math.round(usedGb * 1024) : null,
        totalMb: diskFreeGb != null && diskPct != null && diskPct > 0 ? Math.round(diskFreeGb / (1 - diskPct / 100) * 1024) : null,
        usedPct: diskPct
