      smtp: process.env["SMTP_HOST"] ? { status: "ok", provider: process.env["SMTP_HOST"] } : { status: "not_configured", reason: "SMTP_HOST not set" },
      sms: hasSms ? { status: "ok" } : { status: "not_configured", reason: "No SMS provider env vars set" }
