// ../../lib/auth-utils/src/server.ts
function isAuthMethodEnabled(settings, key, role) {
  const val = settings[key];
  if (!val) return false;
  if (val === "on") return true;
  if (val === "off") return false;
  try {
    const parsed = JSON.parse(val);
    if (role) return (parsed[role] ?? "off") === "on";
    return Object.values(parsed).some((v) => v === "on");
  } catch {
    return val === "on";
  }
}
function isAuthMethodEnabledStrict(settings, newKey, legacyKey, role) {
  const newVal = settings[newKey];
  if (newVal) {
    try {
      const parsed = JSON.parse(newVal);
      if (role && role in parsed) return parsed[role] === "on";
      return false;
    } catch {
      return newVal === "on";
    }
  }
  const legacyVal = settings[legacyKey];
  if (legacyVal) return legacyVal === "on";
  return false;
}

