init_schema();
init_admin_shared();
import { eq as eq12 } from "drizzle-orm";
var VALID_LANGUAGES = ["en", "ur", "roman"];
async function getPlatformDefaultLanguage() {
  try {
    const s = await getPlatformSettings();
    const lang = s["default_language"];
    if (lang && VALID_LANGUAGES.includes(lang)) return lang;
  } catch (err) {
    void err;
  }
  return "en";
}
async function getUserLanguage2(userId) {
  try {
    const [settings] = await db.select({ language: userSettingsTable.language }).from(userSettingsTable).where(eq12(userSettingsTable.userId, userId)).limit(1);
    if (settings?.language && VALID_LANGUAGES.includes(settings.language)) {
      return settings.language;
    }
  } catch (err) {
    void err;
  }
  return getPlatformDefaultLanguage();
}

