// ../../lib/phone-utils/src/index.ts
function canonicalizePhone(raw) {
  const cleaned = raw.replace(/[\s\-()+]/g, "");
  const e164Match = cleaned.match(/^(?:\+?92)(3\d{9})$/);
  if (e164Match) return e164Match[1];
  const localMatch = cleaned.match(/^0(3\d{9})$/);
  if (localMatch) return localMatch[1];
  const bareMatch = cleaned.match(/^(3\d{9})$/);
  if (bareMatch) return bareMatch[1];
  return cleaned;
}
var PHONE_REGEX = /^0?3\d{9}$/;
var CNIC_REGEX = /^\d{5}-\d{7}-\d{1}$/;

// src/routes/auth/helpers.ts
import crypto12, { createHash as createHash3, createHmac as createHmac2, randomBytes as randomBytes5 } from "crypto";
import { and as and8, eq as eq14, lt as lt3, sql as sql15 } from "drizzle-orm";
import { z as z4 } from "zod";

// src/lib/crypto/encryption.ts
init_logger();
import crypto11 from "crypto";
var ALGORITHM = "aes-256-gcm";
var IV_LEN = 12;
var TAG_LEN = 16;
var KEY_ITERS = 1e5;
var SALT = Buffer.from("ajkmart-pii-salt-v1", "utf-8");
var _cachedKey = null;
function deriveKey() {
  if (_cachedKey) return _cachedKey;
  const masterKey = process.env["ENCRYPTION_MASTER_KEY"];
  if (!masterKey || masterKey.length < 16) {
    throw new Error(
      "[encryption] ENCRYPTION_MASTER_KEY is not set or too short (minimum 16 chars). Add this secret in the Replit Secrets panel."
    );
  }
  _cachedKey = crypto11.pbkdf2Sync(Buffer.from(masterKey, "utf-8"), SALT, KEY_ITERS, 32, "sha256");
  return _cachedKey;
}
function encrypt(plaintext) {
  const key = deriveKey();
  const iv = crypto11.randomBytes(IV_LEN);
  const cipher = crypto11.createCipheriv(ALGORITHM, key, iv, { authTagLength: TAG_LEN });
  const encrypted = Buffer.concat([cipher.update(Buffer.from(plaintext, "utf-8")), cipher.final()]);
  const authTag = cipher.getAuthTag();
  return Buffer.concat([iv, authTag, encrypted]).toString("hex");
}
function decrypt(ciphertext) {
  const key = deriveKey();
  const buf = Buffer.from(ciphertext, "hex");
  if (buf.length < IV_LEN + TAG_LEN + 1) {
    throw new Error("[encryption] Ciphertext is too short \u2014 data may be corrupt");
  }
  const iv = buf.subarray(0, IV_LEN);
  const authTag = buf.subarray(IV_LEN, IV_LEN + TAG_LEN);
  const data = buf.subarray(IV_LEN + TAG_LEN);
  const decipher = crypto11.createDecipheriv(ALGORITHM, key, iv, { authTagLength: TAG_LEN });
  decipher.setAuthTag(authTag);
  const decrypted = Buffer.concat([decipher.update(data), decipher.final()]);
  return decrypted.toString("utf-8");
}
function isEncryptionAvailable() {
  try {
    deriveKey();
    return true;
  } catch (err) {
    logger.error(
      {
        error: err instanceof Error ? err.message : String(err),
        timestamp: (/* @__PURE__ */ new Date()).toISOString()
      },
      "[route] unhandled error"
    );
    return false;
  }
}

