router35.post("/riders/:id/bonus", async (req, res) => {
  try {
    const { amount, description } = req.body;
    if (!amount || isNaN(Number(amount)) || Number(amount) <= 0) {
      sendValidationError(res, "Valid amount required");
      return;
    }
    const riderId = req.params["id"];
    const amt = Number(amount);
    const txId = generateId();
    const bonusSettings = await getCachedSettings2();
    const maxBalance = parseFloat(bonusSettings["wallet_max_balance"] ?? "50000");
    let updated;
    let newBal = 0;
    try {
      await db.transaction(async (tx) => {
        const [rider] = await tx.select().from(usersTable).where(eq54(usersTable.id, riderId)).limit(1).for("update");
        if (!rider) throw new Error("NOT_FOUND");
        const currentBal = parseFloat(rider.walletBalance ?? "0");
        if (currentBal + amt > maxBalance) throw new Error("BALANCE_CAP");
        const [refreshed] = await tx.update(usersTable).set({
          walletBalance: sql36`wallet_balance + ${amt}`,
          updatedAt: /* @__PURE__ */ new Date()
        }).where(
          and32(
            eq54(usersTable.id, riderId),
            sql36`CAST(wallet_balance AS numeric) + ${amt} <= ${maxBalance}`
          )
        ).returning();
        if (!refreshed) throw new Error("BALANCE_CAP");
        await tx.insert(walletTransactionsTable).values({
          id: txId,
          userId: riderId,
          type: "credit",
          amount: String(amt),
          description: description || `Admin bonus: Rs. ${amt}`,
          reference: "rider_bonus"
        });
        updated = refreshed;
        newBal = parseFloat(refreshed.walletBalance ?? "0");
      });
    } catch (err) {
      if (err instanceof Error && err.message === "NOT_FOUND") {
        sendNotFound(res, "Rider not found");
        return;
      }
      if (err instanceof Error && err.message === "BALANCE_CAP") {
        sendValidationError(
          res,
          `Wallet balance limit is Rs. ${maxBalance}. Bonus would exceed the limit.`
        );
        return;
      }
      throw err;
    }
    await sendUserNotification(
      riderId,
      "Bonus Received! \u{1F389}",
      `Rs. ${amt} bonus has been added to your wallet.`,
      "system",
      "gift-outline"
    );
    sendSuccess(res, {
      amount: amt,
      newBalance: newBal,
      rider: { ...updated, walletBalance: newBal }
    });
  } catch (err) {
    logger.error(
      {
        error: err instanceof Error ? err.message : String(err),
        timestamp: (/* @__PURE__ */ new Date()).toISOString()
      },
      "[route] unhandled error"
    );
    res.status(500).json({ success: false, error: "Internal server error" });
  }
});
