router35.get(
  "/withdrawal-requests",
  requirePermission("finance.withdrawals.view"),
  async (req, res) => {
    try {
      const statusFilter = req.query["status"];
      const pageNum = Math.max(1, parseInt(String(req.query["page"] ?? "1"), 10) || 1);
      const pageSize = Math.min(
        200,
        Math.max(1, parseInt(String(req.query["limit"] ?? "50"), 10) || 50)
      );
      const offset = (pageNum - 1) * pageSize;
      const statusToRefPattern = {
        pending: "pending",
        paid: "paid:",
        rejected: "rejected:"
      };
      let baseWhere = eq54(walletTransactionsTable.type, "withdrawal");
      if (statusFilter && statusFilter in statusToRefPattern) {
        const pattern = statusToRefPattern[statusFilter];
        if (pattern === "pending") {
          baseWhere = and32(
            baseWhere,
            sql36`(${walletTransactionsTable.reference} = 'pending' OR ${walletTransactionsTable.reference} IS NULL)`
          );
        } else {
          baseWhere = and32(
            baseWhere,
            sql36`${walletTransactionsTable.reference} LIKE ${pattern + "%"}`
          );
        }
      }
      const [{ total }] = await db.select({ total: count7() }).from(walletTransactionsTable).where(baseWhere);
      const rows = await db.select({
        tx: walletTransactionsTable,
        uid: usersTable.id,
        name: usersTable.name,
        phone: usersTable.phone,
        roles: usersTable.roles
      }).from(walletTransactionsTable).leftJoin(usersTable, eq54(walletTransactionsTable.userId, usersTable.id)).where(baseWhere).orderBy(desc14(walletTransactionsTable.createdAt)).limit(pageSize).offset(offset);
      const withdrawals = rows.map(({ tx, uid, name, phone, roles }) => {
        const ref = tx.reference ?? "pending";
        const status = ref === "pending" ? "pending" : ref.startsWith("paid:") ? "paid" : ref.startsWith("rejected:") ? "rejected" : ref;
        const refNo = ref.startsWith("paid:") ? ref.slice(5) : ref.startsWith("rejected:") ? ref.slice(9) : "";
        return {
          ...tx,
          amount: parseFloat(String(tx.amount)),
          user: uid ? { id: uid, name, phone, roles } : null,
          status,
          refNo
        };
      });
      sendSuccess(res, {
        withdrawals,
        total: total ?? 0,
        page: pageNum,
        pageSize
      });
    } catch (err) {
      logger.error(
        {
          error: err instanceof Error ? err.message : String(err),
          timestamp: (/* @__PURE__ */ new Date()).toISOString()
        },
        "[route] unhandled error"
      );
      res.status(500).json({ success: false, error: "Internal server error" });
    }
  }
);
