router35.post("/riders/:id/credit", requirePermission("finance.wallet.adjust"), async (req, res) => {
  try {
    const { amount, description, type } = req.body;
    if (!amount || isNaN(Number(amount)) || Number(amount) <= 0) {
      sendValidationError(res, "Valid amount required");
      return;
    }
    const [rider] = await db.select().from(usersTable).where(eq54(usersTable.id, req.params["id"])).limit(1);
    if (!rider) {
      sendNotFound(res, "Rider not found");
      return;
    }
    const roles = (rider.roles || "").split(",").map((r) => r.trim());
    if (!roles.includes("rider")) {
      sendValidationError(res, "User is not a rider");
      return;
    }
    const amt = Number(amount);
    const txType = type === "bonus" ? "bonus" : "credit";
    const creditSettings = await getCachedSettings2();
    const maxBalance = parseFloat(creditSettings["wallet_max_balance"] ?? "50000");
    let updated;
    try {
      await db.transaction(async (tx) => {
        const [locked] = await tx.select().from(usersTable).where(eq54(usersTable.id, rider.id)).limit(1).for("update");
        if (!locked) throw new Error("NOT_FOUND");
        const currentBal = parseFloat(locked.walletBalance ?? "0");
        if (currentBal + amt > maxBalance) throw new Error("BALANCE_CAP");
        const [txUpdated] = await tx.update(usersTable).set({
          walletBalance: sql36`wallet_balance + ${amt}`,
          updatedAt: /* @__PURE__ */ new Date()
        }).where(
          and32(
            eq54(usersTable.id, rider.id),
            sql36`CAST(wallet_balance AS numeric) + ${amt} <= ${maxBalance}`
          )
        ).returning();
        if (!txUpdated) throw new Error("BALANCE_CAP");
        await tx.insert(walletTransactionsTable).values({
          id: generateId(),
          userId: rider.id,
          type: txType,
          amount: String(amt),
          description: description || `Admin credit: Rs. ${amt}`,
          reference: txType === "bonus" ? "rider_bonus" : "admin_credit"
        });
        updated = txUpdated;
      });
    } catch (err) {
      if (err instanceof Error && err.message === "BALANCE_CAP") {
        sendValidationError(
          res,
          `Wallet balance limit is Rs. ${maxBalance}. Credit would exceed the limit.`
        );
        return;
      }
      throw err;
    }
    await sendUserNotification(
      rider.id,
      txType === "bonus" ? "Bonus Received! \u{1F389}" : "Wallet Credited \u{1F4B0}",
      `Rs. ${amt} aapke wallet mein add ho gaya. ${description || ""}`,
      "wallet",
      "wallet-outline"
    );
    sendSuccess(res, {
      amount: amt,
      newBalance: parseFloat(updated?.walletBalance ?? "0")
    });
  } catch (err) {
    logger.error(
      {
        error: err instanceof Error ? err.message : String(err),
        timestamp: (/* @__PURE__ */ new Date()).toISOString()
      },
      "[route] unhandled error"
    );
    res.status(500).json({ success: false, error: "Internal server error" });
  }
});
