router76.patch("/:id/status", riderAuth, async (req, res, next) => {
  try {
    const riderId = req.riderId;
    const { status } = req.body;
    const allowedStatuses = ["accepted", "picked_up", "in_transit", "delivered", "cancelled"];
    if (!allowedStatuses.includes(status)) {
      sendValidationError(res, `Invalid status. Allowed: ${allowedStatuses.join(", ")}`);
      return;
    }
    const [booking] = await db.select().from(parcelBookingsTable).where(eq96(parcelBookingsTable.id, String(req.params["id"]))).limit(1);
    if (!booking) {
      sendNotFound(res, "Parcel booking not found");
      return;
    }
    const PARCEL_STATUS_ORDER = {
      pending: ["accepted", "cancelled"],
      accepted: ["picked_up", "cancelled"],
      picked_up: ["in_transit", "cancelled"],
      in_transit: ["delivered", "cancelled"],
      delivered: [],
      cancelled: []
    };
    const allowedNext = PARCEL_STATUS_ORDER[booking.status] ?? [];
    if (!allowedNext.includes(status)) {
      sendValidationError(res, `Cannot transition from '${booking.status}' to '${status}'`);
      return;
    }
    const isUnassigned = !booking.riderId;
    const isAssignedToMe = booking.riderId === riderId;
    if (!isUnassigned && !isAssignedToMe) {
      sendForbidden(res, "This parcel is assigned to another rider");
      return;
    }
    if ((status === "accepted" || status === "picked_up") && isUnassigned) {
      const [updated] = await db.update(parcelBookingsTable).set({ status, riderId, updatedAt: /* @__PURE__ */ new Date() }).where(
        and57(eq96(parcelBookingsTable.id, String(req.params["id"])), sql62`rider_id IS NULL`)
      ).returning();
      if (!updated) {
        sendError(res, "This parcel has already been accepted by another rider", 409);
        return;
      }
      sendSuccess(res, mapBooking(updated));
    } else {
      const [updated] = await db.update(parcelBookingsTable).set({ status, riderId, updatedAt: /* @__PURE__ */ new Date() }).where(eq96(parcelBookingsTable.id, String(req.params["id"]))).returning();
      if (!updated) {
        sendNotFound(res, "Parcel booking not found");
        return;
      }
      sendSuccess(res, mapBooking(updated));
    }
  } catch (err) {
    next(err);
  }
});
