async function handleCancelPenalty(riderId) {
  const s = await getCachedSettings();
  const limit = parseInt(s["rider_cancel_limit_daily"] ?? "3", 10);
  const penaltyAmt = parseFloat(s["rider_cancel_penalty_amount"] ?? "50");
  const restrictEnabled = (s["rider_cancel_restrict_enabled"] ?? "on") === "on";
  const today = /* @__PURE__ */ new Date();
  today.setHours(0, 0, 0, 0);
  let penaltyApplied = 0;
  let restricted = false;
  let dailyCancels = 0;
  await db.transaction(async (tx) => {
    const [countRow] = await tx.select({ c: count26() }).from(walletTransactionsTable).where(
      and70(
        eq112(walletTransactionsTable.userId, riderId),
        eq112(walletTransactionsTable.type, "cancel_penalty"),
        gte25(walletTransactionsTable.createdAt, today),
        sql70`reference LIKE 'cancel:%'`
      )
    );
    dailyCancels = (countRow?.c ?? 0) + 1;
    await tx.insert(walletTransactionsTable).values({
      id: generateId(),
      userId: riderId,
      type: "cancel_penalty",
      amount: "0",
      description: `Cancellation #${dailyCancels} today`,
      reference: `cancel:${randomUUID5()}`
    });
    await tx.update(usersTable).set({ cancelCount: sql70`cancel_count + 1`, updatedAt: /* @__PURE__ */ new Date() }).where(eq112(usersTable.id, riderId));
    if (dailyCancels > limit) {
      penaltyApplied = penaltyAmt;
      await tx.update(usersTable).set({
        walletBalance: sql70`GREATEST(wallet_balance - ${penaltyAmt}, 0)`,
        updatedAt: /* @__PURE__ */ new Date()
      }).where(eq112(usersTable.id, riderId));
      await tx.insert(walletTransactionsTable).values({
        id: generateId(),
        userId: riderId,
        type: "cancel_penalty",
        amount: penaltyAmt.toFixed(2),
        description: `Excessive cancellation penalty (${dailyCancels}/${limit} today) \u2014 Rs. ${penaltyAmt} deducted`,
        reference: `cancel_penalty:${randomUUID5()}`
      });
      await tx.insert(riderPenaltiesTable).values({
        id: generateId(),
        riderId,
        type: "cancel",
        amount: penaltyAmt.toFixed(2),
        reason: `Excessive cancellation (${dailyCancels}/${limit} today)`
      });
      if (restrictEnabled) {
        await tx.update(usersTable).set({ isRestricted: true, updatedAt: /* @__PURE__ */ new Date() }).where(eq112(usersTable.id, riderId));
        restricted = true;
      }
    }
  });
  if (dailyCancels > limit) {
    const penaltyLang = await getUserLanguage2(riderId);
    await db.insert(notificationsTable).values({
      id: generateId(),
      userId: riderId,
      title: restricted ? t("notifAccountRestricted", penaltyLang) + " \u26A0\uFE0F" : t("notifCancelPenalty", penaltyLang) + " \u26A0\uFE0F",
      body: restricted ? t("notifCancelRestrictedBody", penaltyLang).replace("{count}", String(dailyCancels)).replace("{limit}", String(limit)).replace("{amount}", String(penaltyAmt)) : t("notifCancelPenaltyBody", penaltyLang).replace("{count}", String(dailyCancels)).replace("{limit}", String(limit)).replace("{amount}", String(penaltyAmt)),
      type: "system",
      icon: "alert-circle-outline"
    }).catch((e) => {
      logger.warn(
        { riderId, err: e.message },
        "[rider] cancel-penalty notification insert failed"
      );
    });
  } else if (dailyCancels === limit) {
    const warnLang = await getUserLanguage2(riderId);
    await db.insert(notificationsTable).values({
      id: generateId(),
      userId: riderId,
      title: t("notifCancelWarning", warnLang) + " \u26A0\uFE0F",
      body: t("notifCancelWarningBody", warnLang).replace("{count}", String(dailyCancels)).replace("{limit}", String(limit)).replace("{amount}", String(penaltyAmt)),
      type: "system",
      icon: "alert-circle-outline"
    }).catch((e) => {
      logger.warn(
        { riderId, err: e.message },
        "[rider] cancel-warning notification insert failed"
      );
    });
  }
  return { dailyCancels, penaltyApplied, restricted };
}
