function assignVariant(userId, experimentId, variants) {
  const hash = crypto21.createHash("md5").update(`${userId}:${experimentId}`).digest("hex");
  const bucket = parseInt(hash.slice(0, 8), 16) % 100;
  let cumulative = 0;
  for (const v of variants) {
    cumulative += v.weight ?? Math.floor(100 / variants.length);
    if (bucket < cumulative) return v.name ?? "control";
  }
  return variants[variants.length - 1]?.name ?? "control";
}
