router109.post("/undo/:id", async (req, res, next) => {
  const { id } = req.params;
  const [snapshot] = await db.select().from(systemSnapshotsTable).where(eq125(systemSnapshotsTable.id, id));
  if (!snapshot) {
    res.status(404).json({ error: "Snapshot not found. It may have already expired or been dismissed." });
    return;
  }
  if (/* @__PURE__ */ new Date() > snapshot.expiresAt) {
    await db.delete(systemSnapshotsTable).where(eq125(systemSnapshotsTable.id, id));
    res.status(410).json({ error: "Undo window has expired. This action is now permanent." });
    return;
  }
  let tables;
  try {
    tables = JSON.parse(snapshot.tablesJson);
  } catch (err) {
    logger.warn(
      { err: err instanceof Error ? err.message : String(err), code: "SNAPSHOT_PARSE_FAILED" },
      "[system] Snapshot JSON parse failed \u2014 data may be corrupted"
    );
    next(new Error("Snapshot data is corrupted."));
    return;
  }
  const { restored, errors } = await restoreTables(tables);
  if (snapshot.actionId === "reset-settings") {
    invalidateSettingsCache();
  }
  await db.delete(systemSnapshotsTable).where(eq125(systemSnapshotsTable.id, id));
  res.json({
    success: errors.length === 0,
    message: errors.length === 0 ? `Undo complete. "${snapshot.label}" has been reversed.` : `Undo completed with ${errors.length} error(s).`,
    restored,
    errors: errors.length > 0 ? errors : void 0
  });
});
