var SUPER_ADMIN_PRESET_ID = "preset_super_admin";
async function seedRbac() {
  let permissionsInserted = 0;
  let permissionsSkipped = 0;
  for (const perm of RBAC_PERMISSIONS) {
    const result = await db.insert(permissionsTable).values(perm).onConflictDoNothing().returning({ id: permissionsTable.id });
    if (result.length > 0) permissionsInserted++;
    else permissionsSkipped++;
  }
  const roleResult = await db.insert(rolesTable).values({
    id: SUPER_ADMIN_ROLE_ID,
    slug: "super_admin",
    name: "Super Admin",
    description: "Full access to all platform features",
    isBuiltIn: true
  }).onConflictDoNothing().returning({ id: rolesTable.id });
  const roleInserted = roleResult.length > 0;
  for (const perm of RBAC_PERMISSIONS) {
    await db.insert(rolePermissionsTable).values({ roleId: SUPER_ADMIN_ROLE_ID, permissionId: perm.id }).onConflictDoNothing();
  }
  const allPermIds = RBAC_PERMISSIONS.map((p) => p.id);
  const presetResult = await db.insert(adminRolePresetsTable).values({
    id: SUPER_ADMIN_PRESET_ID,
    name: "Super Admin",
    slug: "super_admin",
    description: "Full access to all platform features and settings",
    permissionsJson: JSON.stringify(allPermIds),
    role: "superadmin",
    isBuiltIn: true
  }).onConflictDoNothing().returning({ id: adminRolePresetsTable.id });
  const presetInserted = presetResult.length > 0;
  return { permissionsInserted, permissionsSkipped, roleInserted, presetInserted };
}
